import { useState } from "react";
import { useNavigate, Link } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import "./Auth.css";

export default function Register() {
  const [username, setUsername] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [showPwd, setShowPwd] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const { register } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true); setError("");
    try {
      await register(username, email, password);
      navigate("/");
    } catch (err) {
      setError(err.response?.data?.message || "Registration failed");
    }
    setLoading(false);
  };

  return (
    <div className="auth-page">
      <div className="auth-bg">
        <div className="auth-orb orb1" />
        <div className="auth-orb orb2" />
        <div className="auth-orb orb3" />
        <div className="auth-grid" />
      </div>

      <div className="auth-card">
        <div className="auth-logo-wrap">
          <div className="auth-logo">
            <svg viewBox="0 0 40 40" fill="none" xmlns="http://www.w3.org/2000/svg">
              <circle cx="14" cy="14" r="6" fill="url(#g1)" />
              <circle cx="26" cy="14" r="6" fill="url(#g2)" opacity="0.85" />
              <circle cx="20" cy="26" r="6" fill="url(#g3)" opacity="0.9" />
              <defs>
                <linearGradient id="g1" x1="0" y1="0" x2="1" y2="1">
                  <stop offset="0%" stopColor="#8B5CF6"/>
                  <stop offset="100%" stopColor="#6366F1"/>
                </linearGradient>
                <linearGradient id="g2" x1="0" y1="0" x2="1" y2="1">
                  <stop offset="0%" stopColor="#06B6D4"/>
                  <stop offset="100%" stopColor="#3B82F6"/>
                </linearGradient>
                <linearGradient id="g3" x1="0" y1="0" x2="1" y2="1">
                  <stop offset="0%" stopColor="#8B5CF6"/>
                  <stop offset="100%" stopColor="#06B6D4"/>
                </linearGradient>
              </defs>
            </svg>
          </div>
          <div className="auth-brand">PeerSync</div>
        </div>

        <div className="auth-tagline">Connect. Sync. Belong.</div>

        <h1 className="auth-title">Create account</h1>
        <p className="auth-sub">Join PeerSync today</p>

        {error && <div className="auth-error">{error}</div>}

        <form className="auth-form" onSubmit={handleSubmit}>
          <div className="auth-field">
            <label className="auth-label">USERNAME</label>
            <div className="auth-input-wrap">
              <span className="auth-input-icon">@</span>
              <input className="auth-input" type="text" placeholder="Pick a username"
                value={username} onChange={e => setUsername(e.target.value)} required />
            </div>
          </div>

          <div className="auth-field">
            <label className="auth-label">EMAIL</label>
            <div className="auth-input-wrap">
              <span className="auth-input-icon">✉</span>
              <input className="auth-input" type="email" placeholder="your@email.com"
                value={email} onChange={e => setEmail(e.target.value)} required />
            </div>
          </div>

          <div className="auth-field">
            <label className="auth-label">PASSWORD</label>
            <div className="auth-input-wrap">
              <span className="auth-input-icon">🔑</span>
              <input className="auth-input" type={showPwd ? "text" : "password"}
                placeholder="Min 6 characters"
                value={password} onChange={e => setPassword(e.target.value)} required minLength={6} />
              <button type="button" className="auth-eye" onClick={() => setShowPwd(!showPwd)}>
                {showPwd ? "🙈" : "👁"}
              </button>
            </div>
          </div>

          <button className="auth-btn" type="submit" disabled={loading}>
            {loading ? <span className="auth-spinner" /> : <>Create Account 🎉</>}
          </button>
        </form>

        <p className="auth-switch">
          Already have an account? <Link to="/login">Sign In</Link>
        </p>
      </div>
    </div>
  );
}
